import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you create a monthly budget?", a: "Start with monthly income, list every expense category, compare spending to income, then assign money to needs, wants, savings, and debt goals." },
  { q: "What is the 50/30/20 budget rule?", a: "The 50/30/20 rule suggests spending up to 50% of income on needs, 30% on wants, and at least 20% on savings or debt payoff." },
  { q: "How much should you spend on housing?", a: "Many budgets target housing near 25% to 30% of income, though the right amount depends on debt, location, savings goals, and family needs." },
  { q: "How do you build an emergency fund?", a: "Set a monthly savings target and keep the money in a safe, liquid account until you have several months of essential expenses saved." },
  { q: "What is zero-based budgeting?", a: "Zero-based budgeting assigns every dollar of income to a job, so income minus expenses, savings, and debt payments equals zero." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function BudgetCalculator() {
  useCurrencyVersion();
  const [income, setIncome] = useState(5000);
  const [housing, setHousing] = useState(1500);
  const [food, setFood] = useState(600);
  const [transport, setTransport] = useState(400);
  const [utilities, setUtilities] = useState(250);
  const [entertainment, setEntertainment] = useState(350);
  const [savings, setSavings] = useState(800);
  const [debt, setDebt] = useState(300);
  const [other, setOther] = useState(200);
  const result = useMemo(() => {
    const total = housing + food + transport + utilities + entertainment + savings + debt + other;
    const remaining = income - total;
    const savingsRate = income ? savings / income * 100 : 0;
    const needs = housing + food + transport + utilities;
    const wants = entertainment + other;
    return { total, remaining, savingsRate, needs, wants };
  }, [income, housing, food, transport, utilities, entertainment, savings, debt, other]);
  const incomes = [2000, 3000, 4000, 5000, 7500, 10000];
  return (
    <>
      <SEOHead title="Free Budget Calculator Online - Calculate Your Monthly Budget Instantly | CalcHive" description="Free online budget calculator. Calculate your monthly budget breakdown, savings rate and see how your spending compares to the 50/30/20 rule instantly. 100% free, no signup required." canonical="/budget-calculator" keywords="free budget calculator, monthly budget calculator free online, personal budget calculator free, 50 30 20 rule calculator free, budget planner free online" category="Financial Calculators" breadcrumbName="Free Budget Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Budget Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Plan monthly spending, savings, debt payments, and compare your budget to the 50/30/20 rule.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">{[["Monthly income", income, setIncome], ["Housing", housing, setHousing], ["Food", food, setFood], ["Transport", transport, setTransport], ["Utilities", utilities, setUtilities], ["Entertainment", entertainment, setEntertainment], ["Savings", savings, setSavings], ["Debt payments", debt, setDebt], ["Other", other, setOther]].map(([label, value, setter]) => <div key={String(label)}><label className="text-sm font-semibold text-foreground block mb-2">{String(label)}</label><input type="number" value={Number(value)} onChange={(e) => (setter as (v: number) => void)(Number(e.target.value))} className={inputClass} /></div>)}</div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Remaining Income</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.remaining)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total expenses</p><p className="text-lg font-extrabold text-foreground">{money(result.total)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Savings rate</p><p className="text-lg font-extrabold text-foreground">{pct(result.savingsRate)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">50/30/20 needs</p><p className="text-lg font-extrabold text-foreground">{pct(income ? result.needs / income * 100 : 0)}</p></div></div>
          <div className="overflow-x-auto mt-5"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Budget Category Table</caption><tbody className="divide-y divide-border">{[["Needs", result.needs, 50], ["Wants", result.wants, 30], ["Savings", savings, 20], ["Debt payments", debt, 0]].map(([label, value, target]) => <tr key={String(label)}><td className="py-2.5 px-3 font-semibold">{String(label)}</td><td className="py-2.5 px-3">{money(Number(value))}</td><td className="py-2.5 px-3">{pct(income ? Number(value) / income * 100 : 0)}</td><td className="py-2.5 px-3">{Number(target) ? `Target: ${target}%` : "Extra payoff"}</td></tr>)}</tbody></table></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate and Plan Your Monthly Budget for Free</h2><p className="text-muted-foreground leading-relaxed">Enter monthly income and spending categories to see expenses, leftover income, and savings rate.</p><h2 className="text-2xl font-bold text-foreground">How the 50/30/20 Budget Rule Works</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">50/30/20 Budget Breakdown by Monthly Income</caption><thead className="bg-muted/60"><tr>{["Monthly Income", "50% Needs Max", "30% Wants Max", "20% Savings Min", "Recommended Rent (30% of 50%)"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{incomes.map((i) => <tr key={i}><td className="py-2.5 px-3 font-semibold">{money(i, 0)}</td><td className="py-2.5 px-3">{money(i * .5)}</td><td className="py-2.5 px-3">{money(i * .3)}</td><td className="py-2.5 px-3">{money(i * .2)}</td><td className="py-2.5 px-3">{money(i * .5 * .3)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Personal Budget Planner for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use this budget planner to spot overspending, protect savings, and keep debt payments visible.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/budget-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


